﻿"use client";

import { cn } from "@/lib/utils";
import type { HTMLMotionProps, Variants } from "motion/react";
import { motion, useAnimation, useReducedMotion } from "motion/react";
import { forwardRef, useCallback, useImperativeHandle, useRef } from "react";

export interface PencilLineIconHandle {
 startAnimation: () => void;
 stopAnimation: () => void;
}

interface PencilLineIconProps extends HTMLMotionProps<"div"> {
 size?: number;
 duration?: number;
 isAnimated?: boolean;
}

const PencilLineIcon = forwardRef<PencilLineIconHandle, PencilLineIconProps>(
 (
  {
   onMouseEnter,
   onMouseLeave,
   className,
   size = 24,
   duration = 1,
   isAnimated = true,
   ...props
  },
  ref,
 ) => {
  const controls = useAnimation();
  const reduced = useReducedMotion();
  const isControlled = useRef(false);

  useImperativeHandle(ref, () => {
   isControlled.current = true;
   return {
    startAnimation: () =>
     reduced ? controls.start("normal") : controls.start("animate"),
    stopAnimation: () => controls.start("normal"),
   };
  });

  const handleEnter = useCallback(
   (e?: React.MouseEvent<HTMLDivElement>) => {
    if (!isAnimated || reduced) return;
    if (!isControlled.current) controls.start("animate");
    else onMouseEnter?.(e as any);
   },
   [controls, reduced, isAnimated, onMouseEnter],
  );

  const handleLeave = useCallback(
   (e?: React.MouseEvent<HTMLDivElement>) => {
    if (!isControlled.current) controls.start("normal");
    else onMouseLeave?.(e as any);
   },
   [controls, onMouseLeave],
  );

  const iconVariants: Variants = {
   normal: { scale: 1 },
   animate: {
    scale: [1, 1.03, 1],
    transition: {
     duration: 0.35 * duration,
     ease: "easeOut",
    },
   },
  };

  const pencilVariants: Variants = {
   normal: { x: 0, y: 0, rotate: 0, pathLength: 1, opacity: 1 },
   animate: {
    x: [0, 1.2, 0],
    y: [0, -0.8, 0],
    rotate: [0, -2, 0],
    pathLength: [0.65, 1],
    opacity: [0.7, 1],
    transition: {
     duration: 0.55 * duration,
     ease: "easeOut",
    },
   },
  };

  const lineVariants: Variants = {
   normal: { pathLength: 1, opacity: 1 },
   animate: {
    pathLength: [0, 1],
    opacity: [0.6, 1],
    transition: {
     duration: 0.4 * duration,
     ease: "easeOut",
     delay: 0.08 * duration,
    },
   },
  };

  return (
   <motion.div
    className={cn("inline-flex items-center justify-center", className)}
    onMouseEnter={handleEnter}
    onMouseLeave={handleLeave}
    {...props}
   >
    <motion.svg
     xmlns="http://www.w3.org/2000/svg"
     width={size}
     height={size}
     viewBox="0 0 24 24"
     fill="none"
     stroke="currentColor"
     strokeWidth="2"
     strokeLinecap="round"
     strokeLinejoin="round"
     animate={controls}
     initial="normal"
     variants={iconVariants}
    >
     <motion.path d="M12 20h9" variants={lineVariants} />
     <motion.path d="m13.5 6.5 4 4" variants={pencilVariants} />
     <motion.path
      d="M3 21v-4.5L14.5 5a2.121 2.121 0 0 1 3 3L6 19.5z"
      variants={pencilVariants}
     />
    </motion.svg>
   </motion.div>
  );
 },
);

PencilLineIcon.displayName = "PencilLineIcon";
export { PencilLineIcon };
